export function getLegalTermBySlug(slug: string): LegalTermPage | undefined {
  return legalTermPages.find((t) => t.slug === slug);
}

export function getAllLegalTermSlugs(): string[] {
  return legalTermPages.map((t) => t.slug);
}

export function getLegalTermsByCategory(category: string): LegalTermPage[] {
  return legalTermPages.filter((t) => t.category === category);
}

export function getLegalTermCategories(): string[] {
  return [...new Set(legalTermPages.map((t) => t.category))].sort();
}

export function searchLegalTermPages(query: string): LegalTermPage[] {
  const q = query.toLowerCase();
  return legalTermPages.filter(
    (t) =>
      t.term.toLowerCase().includes(q) ||
      t.definition.toLowerCase().includes(q) ||
      t.category.toLowerCase().includes(q)
  );
}
